#include <iostream>
#include <string>
#include <unordered_map>

using namespace std;

char firstNonRepeating(string s)
{
    unordered_map<char, int> freq;

    for (char c : s)
    {
        freq[c]++; // Pass 1: count every character
    }

    for (char c : s)
    {
        if (freq[c] == 1) // Pass 2: find the first one that appeared exactly once
        {
            return c;
        }
    }
    return '\0'; // none found
}

int main()
{
    cout << firstNonRepeating("swiss") << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <unordered_map>
#include <algorithm>

using namespace std;

int main()
{
    vector<string> words = {"eat", "tea", "tan", "ate", "nat", "bat"};

    unordered_map<string, vector<string>> groups;

    for (string word : words)
    {
        string key = word;
        sort(key.begin(), key.end()); // "eat" and "tea" both sort to "aet"

        groups[key].push_back(word); // group by that sorted key
    }

    cout << groups.size() << endl;

    return 0;
}

